#!/usr/bin/env bash
# embers listener — auto-replies to a family member's iMessages in your voice
# Configuration lives in ~/.embers/config.sh (generated by install.sh)

set -euo pipefail

CONFIG_FILE="${EMBERS_CONFIG:-$HOME/.embers/config.sh}"
if [[ ! -f "$CONFIG_FILE" ]]; then
    echo "embers: config not found at $CONFIG_FILE" >&2
    echo "run install.sh first" >&2
    exit 1
fi

# shellcheck disable=SC1090
source "$CONFIG_FILE"

: "${RECIPIENT_PHONE:?RECIPIENT_PHONE must be set in config}"
: "${RECIPIENT_NAME:?RECIPIENT_NAME must be set in config}"
: "${SENDER_NAME:?SENDER_NAME must be set in config}"
: "${RELATIONSHIP:?RELATIONSHIP must be set in config}"
: "${TONE_GUIDANCE:=Be warm, casual, short (1-3 sentences). Match their energy.}"
: "${CHECK_INTERVAL:=900}"
: "${PYTHON_BIN:=python3}"
: "${CLAUDE_BIN:=claude}"

STATE_DIR="$HOME/.embers"
LAST_REPLIED_FILE="$STATE_DIR/last-replied"
LOG_FILE="$STATE_DIR/listener.log"
MESSAGES_TOOL="$(/usr/bin/dirname "$0")/messages"

/bin/mkdir -p "$STATE_DIR"

log() {
    echo "$(/bin/date '+%Y-%m-%d %H:%M:%S') $1" >> "$LOG_FILE"
    echo "$(/bin/date '+%H:%M') $1"
}

notify() {
    /usr/bin/osascript -e "display notification \"$2\" with title \"$1\"" 2>/dev/null || true
}

if [[ ! -f "$LAST_REPLIED_FILE" ]]; then
    /bin/date +%s > "$LAST_REPLIED_FILE"
fi

log "embers listener started — checking every $(( CHECK_INTERVAL / 60 )) min, watching $RECIPIENT_NAME ($RECIPIENT_PHONE)"

while true; do
    LAST_REPLIED=$(/bin/cat "$LAST_REPLIED_FILE")

    RESULT=$(LAST_REPLIED="$LAST_REPLIED" RECIPIENT_PHONE="$RECIPIENT_PHONE" SENDER_NAME="$SENDER_NAME" RECIPIENT_NAME="$RECIPIENT_NAME" "$PYTHON_BIN" << 'PYEOF'
import sqlite3, re, os
from pathlib import Path

DB = Path.home() / "Library" / "Messages" / "chat.db"
APPLE_EPOCH = 978307200
PHONE = os.environ["RECIPIENT_PHONE"]
SENDER = os.environ["SENDER_NAME"]
RECIPIENT = os.environ["RECIPIENT_NAME"]

def extract_attributed_text(blob):
    if not blob: return ""
    try:
        decoded = blob.decode("utf-8", errors="replace")
        chunks = re.findall(r'[\x20-\x7e]{5,}', decoded)
        skip = {'NSString','NSAttributed','streamtyped','NSMutable','NSDictionary',
                'NSNumber','NSValue','NSObject','NSData','NSArray','NSKeyedArchiver',
                '__kIM','bplist','X$version','Y$archiver','T$top','X$objects',
                'DDScannerResult','NS.rangeval','NS.special','RelativeDayOfWeek',
                'DayOfWeek','ApproxTime','NoResult','DateTime','U$null','RMSV$class',
                'ZNS.objects','UHours','WNSArray','Wversion','Ydd-result'}
        text_chunks = [c for c in chunks if not any(s in c for s in skip)
                       and not re.match(r'^[A-Z$][a-z$]{0,2}$', c)
                       and not re.match(r'^[\W\d]+$', c)]
        clean = []
        for c in text_chunks:
            if c.startswith(('$', '\\', '^')) or 'bplist' in c: break
            clean.append(c)
        return " ".join(clean).strip()
    except: return ""

try:
    conn = sqlite3.connect(f"file:{DB}?mode=ro", uri=True)
except Exception as e:
    print(f"ERROR|db-open|{e}")
    raise SystemExit

try:
    rows = conn.execute("""
        SELECT m.date, m.is_from_me, m.text, m.attributedBody,
               (m.associated_message_type IS NOT NULL AND m.associated_message_type > 0) as is_reaction
        FROM message m
        JOIN chat_message_join cmj ON m.ROWID = cmj.message_id
        JOIN chat c ON cmj.chat_id = c.ROWID
        WHERE c.chat_identifier = ?
        ORDER BY m.date DESC LIMIT 5
    """, (PHONE,)).fetchall()
except sqlite3.DatabaseError as e:
    print(f"ERROR|db-read|{e}")
    raise SystemExit

if not rows:
    print("NO_MESSAGES")
    raise SystemExit

latest = None
for r in rows:
    if r[4]:
        continue
    text = r[2] or extract_attributed_text(r[3])
    if text:
        latest = r
        break

if not latest:
    print("NO_NEW")
    raise SystemExit

unix_ts = int(latest[0] / 1_000_000_000 + APPLE_EPOCH)
is_from_me = latest[1]
text = latest[2] or extract_attributed_text(latest[3])

if is_from_me:
    print("LAST_IS_OURS")
    raise SystemExit

last_replied = int(os.environ.get("LAST_REPLIED", "0"))
if unix_ts <= last_replied:
    print("ALREADY_SEEN")
    raise SystemExit

context_lines = []
for r in reversed(rows):
    if r[4]: continue
    t = r[2] or extract_attributed_text(r[3])
    if not t: continue
    who = SENDER if r[1] else RECIPIENT
    context_lines.append(f"{who}: {t}")

print(f"NEEDS_REPLY|{unix_ts}")
print("---CONTEXT---")
print("\n".join(context_lines))

conn.close()
PYEOF
    )

    STATUS=$(echo "$RESULT" | /usr/bin/head -1 | /usr/bin/cut -d'|' -f1)

    case "$STATUS" in
        NEEDS_REPLY)
            NEW_TS=$(echo "$RESULT" | /usr/bin/head -1 | /usr/bin/cut -d'|' -f2)
            CONTEXT=$(echo "$RESULT" | /usr/bin/sed '1d;/^---CONTEXT---$/d')

            log "new message from $RECIPIENT_NAME — generating reply"

            PROMPT="You are $SENDER_NAME replying to your $RELATIONSHIP $RECIPIENT_NAME via iMessage. $TONE_GUIDANCE Never identify as AI. Never overthink it.

Recent conversation:
$CONTEXT

Reply to $RECIPIENT_NAME's latest message. Output ONLY the reply text, nothing else."

            REPLY=$("$CLAUDE_BIN" --print -p "$PROMPT" 2>/dev/null | /usr/bin/head -5 | /usr/bin/tr '\n' ' ' | /usr/bin/sed 's/  */ /g' | /usr/bin/sed 's/^ //;s/ $//')

            if [[ -n "$REPLY" && ${#REPLY} -gt 5 && ${#REPLY} -lt 500 ]]; then
                "$MESSAGES_TOOL" send "$RECIPIENT_PHONE" "$REPLY"
                log "replied: $REPLY"
                notify "embers — replied to $RECIPIENT_NAME" "${REPLY:0:80}"
                echo "$NEW_TS" > "$LAST_REPLIED_FILE"
            else
                log "generated reply was empty or too long — skipping"
            fi
            ;;
        ERROR)
            log "error: $RESULT"
            ;;
        *)
            # quiet — no new message
            ;;
    esac

    /bin/sleep "$CHECK_INTERVAL"
done
